    "\14\0\3\35\6\0\11\35\4\0\17\35\1\231\3\35"+
    "\3\0\2\57\24\0\3\136\6\0\4\136\11\0\5\136"+
    "\32\0\1\107\14\0\3\35\6\0\11\35\4\0\20\35"+
    "\1\232\2\35\3\0\2\57\7\0\1\107\14\0\3\35"+
    "\6\0\11\35\4\0\3\35\1\233\17\35\3\0\2\57";

  private static int [] zzUnpacktrans() {
    int [] result = new int[7194];
    int offset = 0;
    offset = zzUnpacktrans(ZZ_TRANS_PACKED_0, offset, result);
    return result;
  }

  private static int zzUnpacktrans(String packed, int offset, int [] result) {
    int i = 0;       /* index in packed string  */
    int j = offset;  /* index in unpacked array */
    int l = packed.length();
    while (i < l) {
      int count = packed.charAt(i++);
      int value = packed.charAt(i++);
      value--;
      do result[j++] = value; while (--count > 0);
    }
    return j;
  }


